SELECT SUM(contribution_count) AS total_contributions
FROM repository_contributors
WHERE user_id = 0 AND repo_id = 1;

SELECT contribution_count
FROM repository_contributors
WHERE repo_id = 1 AND user_id = 1;

SELECT version
FROM repository_releases
WHERE is_draft = 0 AND is_prerelease = 0;

SELECT title
FROM repository_issues
WHERE status = 'open';

SELECT name
FROM repositories
WHERE language_id = (SELECT language_id FROM languages WHERE language_name = 'Python');

SELECT COUNT(*) AS total_releases
FROM repository_releases
WHERE repo_id = 1;

SELECT COUNT(*) AS open_issues_count
FROM repository_issues
WHERE repo_id = 1 AND status = 'open';
